class Solution:
    def minimumBeautifulSubstrings(self, s: str) -> int:
        n = len(s)

        # Precompute all "beautiful" binary strings up to length n
        beautiful = set()
        powers = [1]  # 5^0
        while True:
            # Next power
            nxt = powers[-1] * 5
            if nxt.bit_length() > n:
                break
            powers.append(nxt)

        for p in powers:
            b = bin(p)[2:]
            if len(b) <= n and not b.startswith('0'):
                beautiful.add(b)

        # DP: dp[i] = min substrings to cover s[:i], i in [0..n]
        INF = 10**9
        dp = [INF] * (n + 1)
        dp[0] = 0

        # Only consider substring lengths that exist in beautiful set
        lens = sorted({len(x) for x in beautiful})

        for i in range(n):
            if dp[i] == INF:
                continue
            if s[i] == '0':
                # any substring starting at i would have leading zero -> invalid
                continue
            for L in lens:
                j = i + L
                if j > n:
                    break
                sub = s[i:j]
                if sub in beautiful:
                    dp[j] = min(dp[j], dp[i] + 1)

        return -1 if dp[n] == INF else dp[n]
